var ROOT_FOLDER_ID = '1OG3XrNjb3ETxuUIsDKqBLzq44sNRw7o1';

function doGet(e) {
  var fileId = e && e.parameter && e.parameter.id;
  if (fileId) {
    try {
      var file = DriveApp.getFileById(fileId);
      var content = file.getBlob().getDataAsString();
      return HtmlService.createHtmlOutput(content)
        .setTitle(file.getName().replace('.html', ''))
        .setXFrameOptionsMode(HtmlService.XFrameOptionsMode.ALLOWALL);
    } catch(err) {
      return HtmlService.createHtmlOutput('<p>Error: ' + err.message + '</p>');
    }
  }
  var groups = [];
  var rootFolder = DriveApp.getFolderById(ROOT_FOLDER_ID);
  collectHtmlFiles(rootFolder, '', groups);
  groups.sort(function(a, b) {
    if (a.folder === b.folder) return b.date.localeCompare(a.date);
    if (a.folder === '') return -1;
    if (b.folder === '') return 1;
    return a.folder.localeCompare(b.folder);
  });
  var baseUrl = ScriptApp.getService().getUrl();
  var html = buildIndexHtml(groups, baseUrl);
  return HtmlService.createHtmlOutput(html).setTitle('TeacherOS 教學指南');
}

function collectHtmlFiles(folder, folderPath, results) {
  var files = folder.getFilesByType('text/html');
  while (files.hasNext()) {
    var f = files.next();
    results.push({
      id: f.getId(),
      name: f.getName().replace('.html', ''),
      date: Utilities.formatDate(f.getLastUpdated(), 'Asia/Taipei', 'yyyy-MM-dd'),
      folder: folderPath
    });
  }
  var subfolders = folder.getFolders();
  while (subfolders.hasNext()) {
    var sub = subfolders.next();
    var subPath = folderPath ? folderPath + ' / ' + sub.getName() : sub.getName();
    collectHtmlFiles(sub, subPath, results);
  }
}

function buildIndexHtml(items, baseUrl) {
  var html = '<!DOCTYPE html><html lang="zh-Hant"><head><meta charset="UTF-8">';
  html += '<meta name="viewport" content="width=device-width,initial-scale=1.0">';
  html += '<title>TeacherOS 教學指南</title><style>';
  html += 'body{font-family:"Noto Serif TC",Georgia,serif;max-width:700px;margin:40px auto;padding:0 24px;color:#2a2a2a;background:#faf8f5}';
  html += 'h1{font-size:24px;margin-bottom:8px}';
  html += '.sub{font-size:13px;color:#999;margin-bottom:32px}';
  html += '.group-title{font-size:13px;color:#888;letter-spacing:1px;margin:28px 0 8px;padding-bottom:6px;border-bottom:1px solid #e8e4de}';
  html += '.card{display:block;padding:16px 20px;margin-bottom:10px;background:#fff;border:1px solid #e8e4de;border-radius:8px;text-decoration:none;color:#2a2a2a;transition:border-color .2s}';
  html += '.card:hover{border-color:#c0a060}';
  html += '.card-title{font-size:16px;font-weight:600;margin-bottom:4px}';
  html += '.card-meta{font-size:12px;color:#999}';
  html += '.footer{text-align:center;font-size:11px;color:#bbb;margin-top:48px}';
  html += '.count{font-size:13px;color:#aaa;margin-bottom:24px}';
  html += '</style></head><body>';
  html += '<h1>TeacherOS 教學指南</h1>';
  html += '<div class="sub">點擊任一指南即可瀏覽。將 HTML 放入 Drive「teaching-guides」資料夾（含子資料夾）即自動出現。</div>';
  html += '<div class="count">共 ' + items.length + ' 份指南</div>';

  var currentFolder = null;
  for (var i = 0; i < items.length; i++) {
    var item = items[i];
    if (item.folder !== currentFolder) {
      currentFolder = item.folder;
      html += '<div class="group-title">' + (currentFolder || '根目錄') + '</div>';
    }
    html += '<a class="card" href="' + baseUrl + '?id=' + item.id + '">';
    html += '<div class="card-title">' + item.name + '</div>';
    html += '<div class="card-meta">更新：' + item.date + '</div></a>';
  }

  if (!items.length) html += '<p style="color:#999">目前沒有教學指南。</p>';
  html += '<div class="footer">TeacherOS 教學指南瀏覽器</div>';
  html += '</body></html>';
  return html;
}
